# Check if wasmtime is available
check_wasmtime() {
    if ! command -v wasmtime >/dev/null 2>&1; then
        print_error "wasmtime is not installed or not in PATH"
        print_info "Install wasmtime from: https://wasmtime.dev/"
        exit 1
    fi
}

# Validate arguments
validate_args() {
    if [ $# -lt 2 ]; then
        print_error "Insufficient arguments"
        show_usage
        exit 1
    fi

    local function_name="$1"
    local component_path="$2"

    if [ -z "$function_name" ]; then
        print_error "Function name cannot be empty"
        exit 1
    fi

    if [ ! -f "$component_path" ]; then
        print_error "Component file not found: $component_path"
        exit 1
    fi

    if [[ "$component_path" != *.wasm ]]; then
        print_warning "File does not have .wasm extension: $component_path"
    fi
}

# Run the component
run_component() {
    local function_name="$1"
    local component_path="$2"
    shift 2
    local args=("$@")

    print_info "Running component: $component_path"
    print_info "Function: $function_name"
    if [ ${#args[@]} -gt 0 ]; then
        print_info "Arguments: ${args[*]}"
    fi

    # Build wasmtime command
    local wasmtime_cmd=("wasmtime" "run" "--invoke" "$function_name" "$component_path")
    wasmtime_cmd+=("${args[@]}")

    # Add additional wasmtime arguments if specified
    if [ -n "${WASMTIME_ARGS:-}" ]; then
        print_info "Additional wasmtime args: $WASMTIME_ARGS"
        # Split WASMTIME_ARGS into array
        IFS=' ' read -ra additional_args <<< "$WASMTIME_ARGS"
        wasmtime_cmd+=("${additional_args[@]}")
    fi

    if [ "${VERBOSE:-0}" = "1" ]; then
        print_info "Command: ${wasmtime_cmd[*]}"
    fi

    # Run the component
    local exit_code=0
    local output
    output=$("${wasmtime_cmd[@]}" 2>&1) || exit_code=$?

    if [ $exit_code -eq 0 ]; then
        print_success "Component executed successfully"
        echo "$output"
    else
        print_error "Component execution failed (exit code: $exit_code)"
        echo "$output"
        if [ "${STRICT:-0}" = "1" ]; then
            exit $exit_code
        fi
    fi
}

# Main execution
